export const 天剛聚形 = (bi) => {
    const u = bi.u;
    const k = 1.05;
    const X = (c) => (c - 11.5) * k;
    const Z = (r) => r * k;
    const 線 = (書, 寬 = 0.78) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // ── 天段：二長橫，兩端上翹 ──
    線(p => p.M(X(1.7), Z(1.4)).C(X(1.9), Z(2.1), X(2.3), Z(2.4), X(3.0), Z(2.5))
        .C(X(8.0), Z(2.7), X(15.0), Z(2.7), X(20.2), Z(2.4))
        .C(X(20.9), Z(2.3), X(21.3), Z(1.9), X(21.5), Z(1.2)), 0.8);
    線(p => p.M(X(1.9), Z(3.3)).C(X(2.1), Z(4.0), X(2.5), Z(4.3), X(3.2), Z(4.4))
        .C(X(8.0), Z(4.6), X(14.0), Z(4.6), X(19.9), Z(4.3))
        .C(X(20.6), Z(4.2), X(21.0), Z(3.8), X(21.2), Z(3.1)), 0.8);
    // ── 岡段：圓角冂框 ──
    線(p => p.M(X(2.6), Z(16.3)).L(X(2.6), Z(7.2))
        .C(X(2.6), Z(6.0), X(3.2), Z(5.5), X(4.4), Z(5.5))
        .L(X(19.0), Z(5.3))
        .C(X(20.2), Z(5.3), X(20.7), Z(5.9), X(20.7), Z(7.0))
        .L(X(20.7), Z(16.0)), 0.85);
    // 框內左：从（雙撇）
    線(p => p.M(X(5.8), Z(6.5)).C(X(5.3), Z(8.3), X(4.7), Z(10.1), X(3.9), Z(11.7)), 0.68);
    線(p => p.M(X(7.0), Z(7.1)).C(X(6.5), Z(8.8), X(6.0), Z(10.5), X(5.3), Z(11.9)), 0.68);
    // 框內中：人形雙曲＋頂點
    bi.dot(X(10.4), Z(6.2), 0.3);
    線(p => p.M(X(10.6), Z(6.7)).C(X(10.0), Z(8.5), X(9.3), Z(10.3), X(8.4), Z(11.8)), 0.68);
    線(p => p.M(X(10.2), Z(8.2)).C(X(10.9), Z(9.5), X(11.7), Z(10.7), X(12.5), Z(11.7)), 0.68);
    // 框內右：川三豎（中豎懸針綴點）
    線(p => p.M(X(13.8), Z(5.9)).C(X(13.6), Z(7.8), X(13.5), Z(9.8), X(13.5), Z(11.7)), 0.68);
    線(p => p.M(X(15.9), Z(6.0)).L(X(15.9), Z(10.4)), 0.68);
    bi.dot(X(15.9), Z(11.2), 0.32);
    線(p => p.M(X(18.1), Z(5.9)).L(X(18.1), Z(11.7)), 0.68);
    // 框底中：山
    線(p => p.M(X(11.0), Z(11.9)).L(X(11.0), Z(14.7)), 0.72);
    線(p => p.M(X(7.9), Z(12.4)).L(X(7.9), Z(15.2)).L(X(14.3), Z(15.0)).L(X(14.3), Z(12.3)), 0.7);
    // ── 大聖段：口箱・雙桁・曰箱・耳桁・幺幺・攵 ──
    // 左口箱
    線(p => p.M(X(3.1), Z(16.9)).L(X(3.1), Z(18.9)).L(X(7.5), Z(18.7))
        .L(X(7.5), Z(16.7)).L(X(3.05), Z(16.9)), 0.7);
    // 右雙桁（右端垂鉤）
    線(p => p.M(X(9.4), Z(17.0)).C(X(13.0), Z(16.8), X(16.0), Z(16.7), X(19.2), Z(16.8))
        .C(X(19.8), Z(16.9), X(20.0), Z(17.3), X(19.9), Z(17.8)), 0.7);
    線(p => p.M(X(9.4), Z(18.5)).C(X(13.0), Z(18.3), X(16.0), Z(18.2), X(19.0), Z(18.3))
        .C(X(19.6), Z(18.4), X(19.8), Z(18.8), X(19.7), Z(19.2)), 0.7);
    // 寬曰箱
    線(p => p.M(X(3.5), Z(19.3)).L(X(3.5), Z(21.5)).L(X(19.6), Z(21.2))
        .L(X(19.6), Z(19.0)).L(X(3.45), Z(19.3)), 0.72);
    線(p => p.M(X(3.6), Z(20.3)).L(X(19.5), Z(20.1)), 0.75);
    // 左耳桁（三橫二豎）
    線(p => p.M(X(2.6), Z(22.4)).L(X(9.3), Z(22.2)), 0.7);
    線(p => p.M(X(4.3), Z(22.4)).L(X(4.3), Z(26.9)), 0.68);
    線(p => p.M(X(7.5), Z(22.3)).L(X(7.5), Z(26.8)), 0.68);
    線(p => p.M(X(4.3), Z(24.6)).L(X(7.5), Z(24.5)), 0.75);
    線(p => p.M(X(2.4), Z(26.9)).L(X(9.6), Z(26.6)), 0.72);
    // 幺幺（雙環鏈二道）
    const 幺 = (cx) => 線(p => p
        .M(X(cx + 1.0), Z(21.7))
        .C(X(cx - 0.9), Z(22.3), X(cx - 1.3), Z(23.4), X(cx + 0.1), Z(23.8))
        .C(X(cx + 1.2), Z(24.1), X(cx + 1.6), Z(23.0), X(cx + 0.7), Z(22.6))
        .C(X(cx - 0.8), Z(24.5), X(cx - 1.2), Z(25.6), X(cx + 0.2), Z(26.0))
        .C(X(cx + 1.3), Z(26.4), X(cx + 1.7), Z(25.3), X(cx + 0.8), Z(24.8)), 0.75);
    幺(11.9);
    幺(14.6);
    // 攵（右）
    線(p => p.M(X(16.6), Z(22.0)).C(X(16.0), Z(23.2), X(15.3), Z(24.3), X(14.6), Z(25.3)), 0.68);
    線(p => p.M(X(15.2), Z(23.3)).L(X(19.6), Z(23.0)), 0.75);
    線(p => p.M(X(18.2), Z(23.4)).C(X(17.3), Z(24.8), X(16.4), Z(26.1), X(15.4), Z(27.2)), 0.68);
    線(p => p.M(X(16.2), Z(24.6)).C(X(17.3), Z(25.6), X(18.5), Z(26.5), X(19.8), Z(27.3)), 0.68);
    // ── 鉤桁匕曲段 ──
    // 「桁（左端垂鉤起）
    線(p => p.M(X(2.6), Z(29.6)).L(X(2.65), Z(28.5))
        .C(X(2.7), Z(28.2), X(3.0), Z(28.1), X(3.4), Z(28.1))
        .L(X(10.5), Z(27.9)), 0.72);
    // 匕曲三道（右）
    線(p => p.M(X(13.1), Z(27.4)).C(X(12.1), Z(28.8), X(11.1), Z(30.0), X(10.4), Z(30.7))
        .C(X(11.4), Z(31.1), X(12.5), Z(30.8), X(13.5), Z(30.1)), 0.7);
    線(p => p.M(X(16.9), Z(27.3)).C(X(15.9), Z(28.7), X(14.9), Z(29.9), X(14.1), Z(30.8))
        .C(X(15.1), Z(31.2), X(16.2), Z(30.9), X(17.2), Z(30.2)), 0.7);
    線(p => p.M(X(19.6), Z(27.7)).C(X(18.9), Z(28.8), X(18.2), Z(29.9), X(17.5), Z(30.9)), 0.7);
    // 環首桁（左環起，右行）
    線(p => p.M(X(5.4), Z(31.4)).C(X(4.2), Z(31.2), X(3.3), Z(31.9), X(3.7), Z(32.6))
        .C(X(4.0), Z(33.2), X(5.0), Z(33.2), X(5.5), Z(32.6))
        .C(X(7.5), Z(32.4), X(9.8), Z(32.2), X(12.0), Z(32.0)), 0.68);
    // 右二小曲
    線(p => p.M(X(14.0), Z(30.9)).C(X(13.3), Z(31.8), X(13.5), Z(32.8), X(14.5), Z(33.0))
        .C(X(15.3), Z(33.2), X(15.9), Z(32.5), X(15.5), Z(31.7)), 0.75);
    線(p => p.M(X(18.4), Z(31.1)).C(X(17.8), Z(31.9), X(17.9), Z(32.8), X(18.7), Z(33.0)), 0.75);
    // ── 曰箱垂足段 ──
    線(p => p.M(X(5.7), Z(33.9)).L(X(5.7), Z(36.4)).L(X(17.4), Z(36.1))
        .L(X(17.4), Z(33.7)).L(X(5.65), Z(33.9)), 0.75);
    線(p => p.M(X(5.8), Z(35.1)).L(X(17.3), Z(34.9)), 0.75);
    // 垂足四道（蛇曲）
    線(p => p.M(X(6.6), Z(36.6)).C(X(5.6), Z(38.0), X(5.2), Z(39.2), X(6.0), Z(40.0))
        .C(X(6.6), Z(40.6), X(6.2), Z(41.4), X(4.6), Z(41.9))
        .C(X(3.9), Z(42.1), X(3.2), Z(42.1), X(2.8), Z(41.9)), 0.7);
    線(p => p.M(X(9.2), Z(36.6)).C(X(8.6), Z(38.2), X(8.4), Z(39.4), X(9.2), Z(40.3))
        .C(X(9.8), Z(41.0), X(9.2), Z(41.8), X(7.8), Z(42.2)), 0.7);
    線(p => p.M(X(13.2), Z(36.5)).C(X(14.3), Z(38.0), X(14.5), Z(39.3), X(13.4), Z(40.2))
        .C(X(12.5), Z(40.9), X(13.0), Z(41.9), X(14.6), Z(42.3)), 0.7);
    線(p => p.M(X(16.9), Z(36.5)).C(X(18.0), Z(37.8), X(18.3), Z(39.0), X(17.3), Z(39.9))
        .C(X(16.5), Z(40.6), X(17.0), Z(41.5), X(18.4), Z(41.8)), 0.7);
    bi.dot(X(12.2), Z(39.4), 0.28);
};
